// Get the error message
  let errorMessage = "Authentication failed";

  if (context.parameters['error']) {
    // Extract error details
    const errorText = context.parameters['error'].message || context.parameters['error'].error_description || '';

    // Log the error for debugging
    console.log('Auth Error:', context.parameters['error']);

    // Check for email exists error patterns
    if (context.parameters['error'].status === 409 || 
        (errorText && errorText.includes('already exists')) || 
        (errorText && errorText.includes('already registered')) ||
        (context.parameters['error'].code && context.parameters['error'].code === 'already-registered')) {
      errorMessage = "Email already exists or invalid. Please log in instead.";
    } 
    // Other error cases
    else if (errorText.includes('Invalid login credentials')) {
      errorMessage = "Invalid email or password. Please try again.";
    } 
    else if (errorText.includes('network')) {
      errorMessage = "Network error. Please check your connection and try again.";
    } 
    else if (errorText.includes('too many requests')) {
      errorMessage = "Too many attempts. Please try again later.";
    } 
    else if (errorText.includes('Password')) {
      errorMessage = errorText; // Use password validation message directly
    } 
    else if (errorText.includes('required')) {
      errorMessage = "Please fill in all required fields.";
    } 
    else if (errorText.includes('match')) {
      errorMessage = "Passwords do not match. Please try again.";
    } 
    else if (errorText.includes('Invalid email')) {
      errorMessage = "Please enter a valid email address.";
    } 
    else if (context.parameters['error'].message) {
      errorMessage = context.parameters['error'].message;
    }
  }

  // Set the auth error variable directly
  variables['aad5e890-cb44-4993-89e8-b2927223c823'] = errorMessage;

  return { success: false, message: errorMessage };

